    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun createTransactionRequestAccount(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, account: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : CreateTransactionRequestCounterparty200Response {
        val localVarResponse = createTransactionRequestAccountWithHttpInfo(bankid = bankid, accountid = accountid, viewid = viewid, account = account, createTransactionRequestAccountRequest = createTransactionRequestAccountRequest)

