    fun createTransactionRequestAccountWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, account: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : ApiResponse<CreateTransactionRequestCounterparty200Response?> {
