    /**
     * To obtain the request config of the operation createTransactionRequestAccount
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param account The ACCOUNT identifier
     * @param createTransactionRequestAccountRequest Request body
     * @return RequestConfig
     */
    fun createTransactionRequestAccountRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, account: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : RequestConfig<CreateTransactionRequestAccountRequest> {
        val localVariableBody = createTransactionRequestAccountRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v4.0.0/banks/{bankid}/accounts/{accountid}/{viewid}/transaction-request-types/{account}/transaction-requests".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"viewid"+"}", encodeURIComponent(viewid.toString())).replace("{"+"account"+"}", encodeURIComponent(account.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

