    fun createTransactionRequestAccountOtpWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, accountotp: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : ApiResponse<CreateTransactionRequestCounterparty200Response?> {
