    @Throws(IllegalStateException::class, IOException::class)
    fun createTransactionRequestCardWithHttpInfo(card: kotlin.String, createTransactionRequestCardRequest: CreateTransactionRequestCardRequest) : ApiResponse<CreateTransactionRequestCounterparty200Response?> {
