    }

    /**
     * To obtain the request config of the operation createTransactionRequestCard
     *
     * @param card The CARD identifier
     * @param createTransactionRequestCardRequest Request body
     * @return RequestConfig
     */
    fun createTransactionRequestCardRequestConfig(card: kotlin.String, createTransactionRequestCardRequest: CreateTransactionRequestCardRequest) : RequestConfig<CreateTransactionRequestCardRequest> {
        val localVariableBody = createTransactionRequestCardRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v4.0.0/transaction-request-types/{card}/transaction-requests".replace("{"+"card"+"}", encodeURIComponent(card.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

