    fun createTransactionRequestCardanoRequestConfig(bankid: kotlin.String, accountid: kotlin.String, cardano: kotlin.String, createTransactionRequestCardanoRequest: CreateTransactionRequestCardanoRequest) : RequestConfig<CreateTransactionRequestCardanoRequest> {
        val localVariableBody = createTransactionRequestCardanoRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
