    /**
     * To obtain the request config of the operation createTransactionRequestCounterparty
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param counterparty The COUNTERPARTY identifier
     * @param createTransactionRequestCounterpartyRequest Request body
     * @return RequestConfig
     */
    fun createTransactionRequestCounterpartyRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, counterparty: kotlin.String, createTransactionRequestCounterpartyRequest: CreateTransactionRequestCounterpartyRequest) : RequestConfig<CreateTransactionRequestCounterpartyRequest> {
        val localVariableBody = createTransactionRequestCounterpartyRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v4.0.0/banks/{bankid}/accounts/{accountid}/{viewid}/transaction-request-types/{counterparty}/transaction-requests".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"viewid"+"}", encodeURIComponent(viewid.toString())).replace("{"+"counterparty"+"}", encodeURIComponent(counterparty.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

