    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun createTransactionRequestHold(bankid: kotlin.String, accountid: kotlin.String, hold: kotlin.String, createTransactionRequestFreeFormRequest: CreateTransactionRequestFreeFormRequest) : CreateTransactionRequestCounterparty200Response {
        val localVarResponse = createTransactionRequestHoldWithHttpInfo(bankid = bankid, accountid = accountid, hold = hold, createTransactionRequestFreeFormRequest = createTransactionRequestFreeFormRequest)

