    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun createTransactionRequestRefund(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, refund: kotlin.String, createTransactionRequestRefundRequest: CreateTransactionRequestRefundRequest) : CreateTransactionRequestCounterparty200Response {
        val localVarResponse = createTransactionRequestRefundWithHttpInfo(bankid = bankid, accountid = accountid, viewid = viewid, refund = refund, createTransactionRequestRefundRequest = createTransactionRequestRefundRequest)

        return when (localVarResponse.responseType) {
