     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param sandboxtan The SANDBOXTAN identifier
     * @param createTransactionRequestAccountRequest Request body
     * @return ApiResponse<GetTransactionRequestById200Response?>
     * @throws IllegalStateException If the request is not correctly configured
     * @throws IOException Rethrows the OkHttp execute method exception
     */
    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class)
    fun createTransactionRequestSandboxTanWithHttpInfo(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, sandboxtan: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : ApiResponse<GetTransactionRequestById200Response?> {
        val localVariableConfig = createTransactionRequestSandboxTanRequestConfig(bankid = bankid, accountid = accountid, viewid = viewid, sandboxtan = sandboxtan, createTransactionRequestAccountRequest = createTransactionRequestAccountRequest)

        return request<CreateTransactionRequestAccountRequest, GetTransactionRequestById200Response>(
            localVariableConfig
        )
    }

    /**
     * To obtain the request config of the operation createTransactionRequestSandboxTan
     *
     * @param bankid The BANKID identifier
     * @param accountid The ACCOUNTID identifier
     * @param viewid The VIEWID identifier
     * @param sandboxtan The SANDBOXTAN identifier
     * @param createTransactionRequestAccountRequest Request body
     * @return RequestConfig
     */
    fun createTransactionRequestSandboxTanRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, sandboxtan: kotlin.String, createTransactionRequestAccountRequest: CreateTransactionRequestAccountRequest) : RequestConfig<CreateTransactionRequestAccountRequest> {
        val localVariableBody = createTransactionRequestAccountRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v2.1.0/banks/{bankid}/accounts/{accountid}/{viewid}/transaction-request-types/{sandboxtan}/transaction-requests".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"viewid"+"}", encodeURIComponent(viewid.toString())).replace("{"+"sandboxtan"+"}", encodeURIComponent(sandboxtan.toString())),
            query = localVariableQuery,
            headers = localVariableHeaders,
            requiresAuthentication = true,
            body = localVariableBody
        )
    }

    /**
