    @Suppress("UNCHECKED_CAST")
    @Throws(IllegalStateException::class, IOException::class, UnsupportedOperationException::class, ClientException::class, ServerException::class)
    fun createTransactionRequestSepa(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, sepa: kotlin.String, createTransactionRequestSepaRequest: CreateTransactionRequestSepaRequest) : CreateTransactionRequestCounterparty200Response {
        val localVarResponse = createTransactionRequestSepaWithHttpInfo(bankid = bankid, accountid = accountid, viewid = viewid, sepa = sepa, createTransactionRequestSepaRequest = createTransactionRequestSepaRequest)

        return when (localVarResponse.responseType) {
