     * @return RequestConfig
     */
    fun createTransactionRequestSepaRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, sepa: kotlin.String, createTransactionRequestSepaRequest: CreateTransactionRequestSepaRequest) : RequestConfig<CreateTransactionRequestSepaRequest> {
        val localVariableBody = createTransactionRequestSepaRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
        localVariableHeaders["Accept"] = "application/json"

        return RequestConfig(
            method = RequestMethod.POST,
            path = "/obp/v4.0.0/banks/{bankid}/accounts/{accountid}/{viewid}/transaction-request-types/{sepa}/transaction-requests".replace("{"+"bankid"+"}", encodeURIComponent(bankid.toString())).replace("{"+"accountid"+"}", encodeURIComponent(accountid.toString())).replace("{"+"viewid"+"}", encodeURIComponent(viewid.toString())).replace("{"+"sepa"+"}", encodeURIComponent(sepa.toString())),
