    fun createTransactionRequestSimpleRequestConfig(bankid: kotlin.String, accountid: kotlin.String, viewid: kotlin.String, simple: kotlin.String, createTransactionRequestSimpleRequest: CreateTransactionRequestSimpleRequest) : RequestConfig<CreateTransactionRequestSimpleRequest> {
        val localVariableBody = createTransactionRequestSimpleRequest
        val localVariableQuery: MultiValueMap = mutableMapOf()
        val localVariableHeaders: MutableMap<String, String> = mutableMapOf()
        localVariableHeaders["Content-Type"] = "application/json"
